local LModel = LModel
------------------------------------------------------------------
---@class ModelRegression:LModel
local ModelRegression = LxClass("ModelRegression",LModel)
------------------------------------------------------------------
function ModelRegression:ModelRegression()
	self.endTime = 0 -- 活动剩余时间-秒
	self.currentDay = 0 --当前是第几天
	self.starTime = 0--活动开始时间
	
	self.signState = {} --状态（0-未完成,1-可领取,2-已领取）
	self.privilegeList = {} -- 特权列表
	self.giftList = {} --可购买礼包列表
	
	self.monsterEndTime = 0 --剩余时间
	self.monsterList = {} -- 怪物列表

	self.puzzleActivate = {} -- //已激活的拼图下标列表
	self.puzzleRwdGoted = {}--//已领取的拼图奖励refId
end
--模块初始化入口
--注册事件监听
--注册协议监听
--预处理数据
function ModelRegression:OnModelInit()
	self:ModelNetMsgRecv(LProtoIds.RegressionInfoResp,function (...) self:OnRegressionInfoResp(...) end)
	self:ModelNetMsgRecv(LProtoIds.RegressionLoginAwardResp,function (...) self:OnRegressionLoginAwardResp(...) end)
	self:ModelNetMsgRecv(LProtoIds.RegressionPrivilegeResp, function(...) self:OnRegressionPrivilegeResp(...) end)
	self:ModelNetMsgRecv(LProtoIds.RegressionGiftResp, function(...) self:OnRegressionGiftResp(...) end)
	self:ModelNetMsgRecv(LProtoIds.RegressionMonsterResp, function(...) self:OnRegressionMonsterResp(...) end)
	self:ModelNetMsgRecv(LProtoIds.RegressionAssemblyPictureResp, function(...) self:OnRegressionAssemblyPictureResp(...) end)
end

--在协议数据处理完之后需要调用finish
function ModelRegression:OnModelRequest()
	self:ModelFinish()
end

---------------------------------------------------------------------------
--- req
--签到信息
function ModelRegression:OnRegressionLoginAwardReq(refId)
	--refId==0：请求所有签到奖励信息；refId>0:领取指定的奖励
	local pb = LProtoHelper.CreateProto(LProtoIds.RegressionLoginAwardReq)
	pb.refId = refId
	SendMessage(pb,LProtoIds.RegressionLoginAwardReq)
end
--获取特权信息
function ModelRegression:OnRegressionPrivilegeReq()
	local pb = LProtoHelper.CreateProto(LProtoIds.RegressionPrivilegeReq)
	SendMessage(pb,LProtoIds.RegressionPrivilegeReq)
end
--直购礼包信息
function ModelRegression:OnRegressionGiftReq(type,refId,selected)
	local pb = LProtoHelper.CreateProto(LProtoIds.RegressionGiftReq)
	pb.type = type
	pb.refId = refId
	pb.selected = selected
	SendMessage(pb,LProtoIds.RegressionGiftReq)
end
--怪物信息
function ModelRegression:OnRegressionMonsterReq()
	local pb = LProtoHelper.CreateProto(LProtoIds.RegressionMonsterReq)
	SendMessage(pb,LProtoIds.RegressionMonsterReq)
end
--获取/激活拼图数据 /操作类型（0=获取拼图数据，1=激活拼图，2=领取拼图奖励）
function ModelRegression:OnRegressionAssemblyPictureReq(type,refId)
	local pb = LProtoHelper.CreateProto(LProtoIds.RegressionAssemblyPictureReq)
	pb.type = type 
	pb.refId = refId 
	SendMessage(pb,LProtoIds.RegressionAssemblyPictureReq)
end



--回归相关数据
function ModelRegression:OnRegressionInfoResp(pb)
	self.starTime = tonumber(pb.starTime)/1000
	self.endTime = tonumber(pb.endTime)/1000
	self.currentDay = pb.currentDay
end

function ModelRegression:OnRegressionLoginAwardResp(pb)
	--refId==0：请求所有签到奖励信息；refId>0:领取指定的奖励
	for _, value in ipairs(pb.awardInfo) do
		self.signState[value.refId] = value.state--//状态（0-未完成,1-可领取,2-已领取）
	end
end

function ModelRegression:OnRegressionPrivilegeResp(pb)
	for _, value in ipairs(pb.refId) do
		self.privilegeList[value] = value
	end 
end

function ModelRegression:OnRegressionGiftResp(pb)
	for _, value in ipairs(pb.giftList) do
		local giftInfo = self.giftList[value.refId]
		local selectList = {}
		if not string.isempty(value.selected) then 
			local list = string.split(value.selected,",")
			for _, value in ipairs(list) do
				selectList[tonumber(value)] = value
			end
		end
		if not giftInfo then
			self.giftList[value.refId] = {refId = value.refId,buyNum = value.buyNum,selected = selectList}
		else
			giftInfo.buyNum = value.buyNum
			giftInfo.selected = selectList
		end
	end
end

function ModelRegression:OnRegressionMonsterResp(pb)
	-- self.monsterEndTime = GetTimestamp() + pb.endTime
	for _, value in ipairs(pb.refId) do
		self.monsterList[value.refId] = {kill=value.kill,startTime=value.starTime}
	end

end
function ModelRegression:OnRegressionAssemblyPictureResp(pb)
	if pb.type==0 then 
	elseif pb.type==1 then
		GF.ShowMessage(ccClientText(45117))
	end
	local oldList = {}
	if #self.puzzleActivate~=0 then 
		for _, value in ipairs(self.puzzleActivate) do
			oldList[value] = value
		end
	end
	local activeId = 0
	local num = 0
	for _, value in ipairs(pb.activate) do
		self.puzzleActivate[value] = value
		num = num+1
		if not oldList[value] and pb.type==1 then activeId = value end
	end
	for _, value in ipairs(pb.receive) do
		self.puzzleRwdGoted[value] = value
	end

	FireEvent(EventNames.REGRESSION_PUZZLE,{activeId = activeId,allActive = num == tonumber(GameTable.ReturnBackConfigRef.puzzleNums)})
end


----------------------------------------------------------------------------

function ModelRegression:IsOpenRegression()
	local curTime = GetTimestamp()
	return self.endTime > curTime
end	

function ModelRegression:GetRegressionQuestRef(taskType)
	if self.regressionTask then return taskType and self.regressionTask[taskType] or self.regressionTask end
	local regressionRefs = GameTable.ReturnBackActiveTaskRef
	self.regressionTask = {}
	for _, value in pairs(regressionRefs) do
		if not self.regressionTask[value.type] then self.regressionTask[value.type] = {} end
		table.insert(self.regressionTask[value.type],value)
	end
	return taskType and self.regressionTask[taskType] or self.regressionTask
end

function ModelRegression:GetRegressionCallJumpAniStats()
	return tonumber(LPlayerPrefs.regressionCallJumpAni) == 1
end

function ModelRegression:SetRegressionCallJumpAniStats(status)
	local value = status and 1 or 0
	LPlayerPrefs.SetRegressionCallJumpAni(value)
end

function ModelRegression:GetPuzzleRwdState(refId)
	local rwdCfg = GameTable.ReturnBackPuzzleRef[refId]
	if self.puzzleRwdGoted[refId] then return false end
	local conditions = string.split(rwdCfg.condition,";")
		for _, value in ipairs(conditions) do
			if not self.puzzleActivate[tonumber(value)] then 
				return false
			end
		end
	return true
end

function ModelRegression:ActivatePuzzle()
	local refs = GameTable.ReturnBackPuzzleRef
	for _, value in pairs(refs) do
		if not self.puzzleRwdGoted[value.refId] and value.refId~=GameTable.ReturnBackConfigRef.puzzleReward then
			if isTips then GF.ShowMessage(ccClientText(45111))  end
			return false
		end
	end
	return true
	-- return self:OnCheckCost(LxDataHelper.ParseItem(GameTable.ReturnBackConfigRef.puzzleConsume,isTips))
end

function ModelRegression:OnCheckCost(costItem,isTips)
    for _, v in pairs(costItem) do
        local tRefId = v.itemId
        local haveNum = gModelItem:GetNumByRefId(tRefId)
        if haveNum < v.itemNum then
			if isTips then gModelGeneral:OpenGetWayWnd({ itemId = tRefId }) end
			return false
        end
    end
	return true
end

return ModelRegression